                {drugInfoModal.loading ? (
                    <div className="py-8 flex flex-col items-center justify-center text-indigo-600">
                        <BrainCircuit className="w-10 h-10 animate-pulse mb-3" />
                        <p className="font-medium animate-pulse">Consulting AI Knowledge Base...</p>
                    </div>
                ) : (
                    <div>
                        <AiResponseDisplay text={drugInfoModal.content} />
                        <p className="text-[10px] text-slate-400 mt-4 text-center">
                            AI-generated content. Verify with official guidelines.
                        </p>
                    </div>
                )}
            </div>
        </Modal>

        {/* Confirmation Modal */}
        <Modal
            isOpen={confirmConfig.isOpen}
            onClose={() => setConfirmConfig(prev => ({ ...prev, isOpen: false }))}
            title={confirmConfig.title}
        >
            <div className="space-y-4">
                <div className="flex items-start gap-3 text-amber-700 bg-amber-50 p-4 rounded-xl border border-amber-100">
                     <AlertTriangle className="w-6 h-6 flex-shrink-0 mt-0.5" />
                     <p className="text-sm font-medium leading-relaxed">{confirmConfig.message}</p>
                </div>
                <div className="grid grid-cols-2 gap-3 pt-2">
                    <button onClick={() => setConfirmConfig(prev => ({ ...prev, isOpen: false }))} className="w-full py-3 rounded-xl font-bold text-slate-600 bg-slate-100 hover:bg-slate-200 transition-colors">Cancel</button>
                    <button onClick={confirmConfig.onConfirm} className="w-full py-3 rounded-xl font-bold text-white bg-red-600 hover:bg-red-700 shadow-md transition-colors">Confirm</button>
                </div>
            </div>
        </Modal>

      </main>
    </div>
  );
}

