const AiResponseDisplay = ({ text }: { text: string }) => {
  if (!text) return null;

  // Normalize and split lines
  const lines = text.replace(/\r\n/g, '\n').split('\n');
  const elements: React.ReactNode[] = [];
  let listBuffer: React.ReactNode[] = [];

  const flushList = () => {
    if (listBuffer.length > 0) {
      elements.push(
        <ul key={`list-${elements.length}`} className="list-disc pl-5 mb-2 space-y-1">
          {listBuffer}
        </ul>
      );
      listBuffer = [];
    }
  };

  const parseLine = (str: string) => {
    // Basic bold parser: **text**
    const parts = str.split(/(\*\*.*?\*\*)/g);
    return parts.map((part, i) => {
      if (part.startsWith('**') && part.endsWith('**')) {
        return <strong key={i} className="font-bold text-indigo-950 dark:text-indigo-200">{part.slice(2, -2)}</strong>;
      }
      return part;
    });
  };

  lines.forEach((line, i) => {
    const trim = line.trim();
    if (!trim) {
      flushList();
      return;
    }

    if (trim.startsWith('* ') || trim.startsWith('- ') || trim.startsWith('• ')) {
      const content = trim.replace(/^[\*\-\•]\s*/, '');
      listBuffer.push(<li key={`li-${i}`}>{parseLine(content)}</li>);
    } else {
      flushList();
      if (trim.startsWith('### ')) {
        elements.push(<h4 key={`h4-${i}`} className="font-bold text-sm uppercase tracking-wide mt-3 mb-1 text-indigo-800 dark:text-indigo-300">{parseLine(trim.substring(4))}</h4>);
      } else if (trim.startsWith('## ')) {
        elements.push(<h3 key={`h3-${i}`} className="font-bold text-base mt-4 mb-2 text-indigo-900 dark:text-indigo-100">{parseLine(trim.substring(3))}</h3>);
      } else {
        elements.push(<p key={`p-${i}`} className="mb-2 last:mb-0">{parseLine(trim)}</p>);
      }
    }
  });
  flushList();

  return (
    <div className="mt-4 p-4 bg-indigo-50 dark:bg-indigo-950/40 rounded-xl border border-indigo-100 dark:border-indigo-900 text-sm text-indigo-900 dark:text-indigo-200 leading-relaxed animate-in fade-in slide-in-from-top-2 duration-300">
      <div className="flex items-center gap-2 mb-3 border-b border-indigo-200 dark:border-indigo-800 pb-2">
         <BrainCircuit className="w-4 h-4 text-indigo-600 dark:text-indigo-400" />
         <span className="font-bold text-indigo-700 dark:text-indigo-300 text-xs uppercase tracking-wider">AI Assistant Response</span>
      </div>
      <div className="space-y-1">
         {elements}
      </div>
    </div>
  );
};

