      const now = Date.now();
      medications.forEach(med => {
        if (!med.nextDueAt || med.frequency === FrequencyType.PRN || med.isCompleted) return;

        const isDue = med.nextDueAt <= now;
        const isReasonablyRecent = (now - med.nextDueAt) < (24 * 60 * 60 * 1000); 

        if (isDue && isReasonablyRecent) {
          const alertKey = `${med.id}_${med.nextDueAt}`;

          if (!alertedDoses.has(alertKey)) {
            const patient = patients.find(p => p.id === med.patientId);
            const patientName = patient ? patient.name : 'Unknown Patient';

            try {
                new Notification(`Medication Due: ${med.name}`, {
                  body: `${patientName} - ${med.dose} ${med.route}\nDue at ${formatTime(med.nextDueAt)}`,
                  icon: '/favicon.ico', 
                  tag: alertKey
                });
            } catch (e) {
                console.error("Failed to fire notification", e);
            }

            setAlertedDoses(prev => new Set(prev).add(alertKey));
          }
        }
      });
    };

    const intervalId = setInterval(checkDoses, 30000); 
    checkDoses(); 

    return () => clearInterval(intervalId);
  }, [medications, patients, notificationPermission, alertedDoses]);

  // --- ACTIONS ---

  const handleCreateNurse = (e: React.FormEvent<HTMLFormElement>) => {
      e.preventDefault();
      const fd = new FormData(e.currentTarget);
      const name = fd.get('name') as string;
      const initials = fd.get('initials') as string;
      const designation = fd.get('designation') as string;

      // Assign random color
      const color = AVATAR_COLORS[Math.floor(Math.random() * AVATAR_COLORS.length)];

      const newNurse: Nurse = {
          id: generateId(),
          name,
          initials: initials.toUpperCase(),
          designation,
          color
      };

      setNurses(prev => [...prev, newNurse]);
      setCurrentUser(newNurse);
      setIsCreateProfileOpen(false);
  };

  const handleUpdateNurse = (e: React.FormEvent<HTMLFormElement>) => {
      e.preventDefault();
      if (!currentUser) return;
      const fd = new FormData(e.currentTarget);

      const updatedNurse = {
          ...currentUser,
          name: fd.get('name') as string,
          initials: (fd.get('initials') as string).toUpperCase(),
          designation: fd.get('designation') as string,
      };

      setNurses(prev => prev.map(n => n.id === currentUser.id ? updatedNurse : n));
      setCurrentUser(updatedNurse);
      setIsCreateProfileOpen(false);
  };

  const requestNotificationPermission = () => {
    if (!('Notification' in window)) {
      alert("This browser does not support system notifications.");
      return;
    }
    if (window.self !== window.top) {
        alert("Warning: You seem to be using the app inside a preview frame/iframe. Notifications may be blocked by browser security policies. \n\nPlease open the app in a new full tab/window.");
    }
    Notification.requestPermission()
      .then((permission) => {
        setNotificationPermission(permission);
        if (permission === 'denied') {
            alert("Permission was DENIED. You must go to your browser settings and manually allow Notifications for this site.");
        }
      })
      .catch((err) => {
         alert("Error requesting permission: " + err);
      });
  };

  const sendTestNotification = () => {
      if (Notification.permission === 'granted') {
          new Notification("Test Alert", { body: "This is a test notification from NurseFlow." });
      }
  };

  const addPatient = (name: string, roomNumber: string) => {
    const newPatient: Patient = { id: generateId(), name, roomNumber };
    setPatients(prev => [...prev, newPatient]);
    setIsAddPatientOpen(false);
  };

  const updatePatient = (id: string, name: string, roomNumber: string) => {
    setPatients(prev => prev.map(p => p.id === id ? { ...p, name, roomNumber } : p));
    setIsAddPatientOpen(false);
    setEditingPatient(null);
  };

  const deletePatient = (id: string) => {
    setConfirmConfig({
        isOpen: true,
        title: 'Delete Patient?',
        message: 'This will permanently remove the patient and all their records. This action cannot be undone.',
        onConfirm: () => {
            setPatients(prev => prev.filter(p => p.id !== id));
            setMedications(prev => prev.filter(m => m.patientId !== id));
            setView('PATIENTS');
            setConfirmConfig(prev => ({ ...prev, isOpen: false }));
        }
    });
  };

  const addMedication = (med: Omit<Medication, 'id' | 'lastServedAt' | 'nextDueAt' | 'isCompleted'>) => {
    const newMed: Medication = {
      ...med,
      id: generateId(),
      lastServedAt: null,
      nextDueAt: med.frequency === FrequencyType.STAT ? Date.now() : null, 
      isCompleted: false
    };
    setMedications(prev => [...prev, newMed]);
    setIsAddMedOpen(false);
  };

  const updateMedication = (id: string, updates: Partial<Medication>) => {
    setMedications(prev => prev.map(m => {
        if (m.id !== id) return m;
        const updatedMed = { ...m, ...updates };
        if (updates.frequency === FrequencyType.STAT && m.frequency !== FrequencyType.STAT) {
             updatedMed.nextDueAt = Date.now();
        }
        if (updates.intervalHours !== undefined && updates.intervalHours !== m.intervalHours) {
            if (updatedMed.frequency !== FrequencyType.STAT && updatedMed.frequency !== FrequencyType.PRN && m.lastServedAt) {
                 updatedMed.nextDueAt = m.lastServedAt + (updatedMed.intervalHours * 3600000);
            } else if (updatedMed.frequency === FrequencyType.PRN) {
                updatedMed.nextDueAt = null;
            }
        }
        return updatedMed;
    }));
    setIsAddMedOpen(false);
    setEditingMed(null);
  };

  const toggleMedicationComplete = (medId: string) => {
    setMedications(prev => prev.map(m => {
        if (m.id !== medId) return m;
        const isNowCompleted = !m.isCompleted;
        return {
            ...m,
            isCompleted: isNowCompleted,
            nextDueAt: isNowCompleted ? null : Date.now() 
        };
    }));
    if (selectedMedIds.has(medId)) {
        const newSet = new Set(selectedMedIds);
        newSet.delete(medId);
        setSelectedMedIds(newSet);
    }
  };

  const deleteMedication = (id: string) => {
      setConfirmConfig({
        isOpen: true,
        title: 'Delete Medication?',
        message: 'Are you sure you want to remove this medication? All reminders for it will be stopped.',
        onConfirm: () => {
             setMedications(prev => prev.filter(m => m.id !== id));
             setConfirmConfig(prev => ({ ...prev, isOpen: false }));
        }
      });
  };

  const quickServe = (medId: string) => {
    handleManualLog(medId, 'SERVED', Date.now());
  };

  const handleManualLog = (medId: string, status: LogStatus, timestamp: number, notes?: string) => {
    const med = medications.find(m => m.id === medId);
    if (!med) return;

    let nextDue: number | null = med.nextDueAt;
    let isNowCompleted = med.isCompleted;

    if (med.frequency === FrequencyType.STAT) {
        nextDue = null;
        isNowCompleted = true; 
    } else if (med.frequency !== FrequencyType.PRN) {
        if (status === 'SERVED') {
            nextDue = timestamp + (med.intervalHours * 60 * 60 * 1000);
        } else if (status === 'MISSED') {
            if (med.nextDueAt) {
                nextDue = med.nextDueAt + (med.intervalHours * 60 * 60 * 1000);
            } else {
                nextDue = timestamp + (med.intervalHours * 60 * 60 * 1000);
            }
        }
    }

    setMedications(prev => prev.map(m => {
        if (m.id !== medId) return m;
        return {
            ...m,
            lastServedAt: status === 'SERVED' ? timestamp : m.lastServedAt,
            nextDueAt: nextDue,
            isCompleted: isNowCompleted
        };
    }));

    setLogs(prev => [...prev, { 
        id: generateId(), 
        medicationId: medId, 
        servedAt: timestamp, 
        status,
        notes,
        nurseId: currentUser?.id,
        nurseName: currentUser?.name,
        nurseInitials: currentUser?.initials
    }]);

    setLoggingMed(null);
  };

  const toggleMedSelection = (medId: string) => {
    const newSet = new Set(selectedMedIds);
    if (newSet.has(medId)) {
        newSet.delete(medId);
    } else {
        newSet.add(medId);
    }
    setSelectedMedIds(newSet);
  };

  const handleBulkServe = () => {
    if (selectedMedIds.size === 0) return;
    const now = Date.now();
    selectedMedIds.forEach(id => {
        handleManualLog(id, 'SERVED', now, 'Batch served');
    });
    setSelectedMedIds(new Set());
  };

  const handleAskAi = async () => {
    if (!aiQuery.trim()) return;
    setIsAiLoading(true);
    setAiResponse('');
    const answer = await askDrugInfo(aiQuery);
    setAiResponse(answer);
    setIsAiLoading(false);
  };

  const openDrugInfo = async (medName: string) => {
    setDrugInfoModal({ isOpen: true, medName, loading: true, content: '' });
    const response = await askDrugInfo(`Provide a concise clinical summary for ${medName} including indications, common dosage, and key nursing warnings/adverse effects. Keep it under 100 words.`);
    setDrugInfoModal(prev => ({ ...prev, loading: false, content: response }));
  };

  // Voice Inputs
  const startRecording = async () => {
    try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        const mimeType = MediaRecorder.isTypeSupported('audio/webm') ? 'audio/webm' : 'audio/mp4';
        const recorder = new MediaRecorder(stream, { mimeType });
        mediaRecorderRef.current = recorder;
        audioChunksRef.current = [];
        recorder.ondataavailable = (event) => {
            if (event.data.size > 0) audioChunksRef.current.push(event.data);
        };
        recorder.onstop = async () => {
            setIsProcessingAudio(true);
            const blob = new Blob(audioChunksRef.current, { type: mimeType });
            const reader = new FileReader();
            reader.readAsDataURL(blob);
            reader.onloadend = async () => {
                const base64data = (reader.result as string).split(',')[1];
                try {
                    const result = await parseMedicationFromAudio(base64data, mimeType);
                    if (result.name && nameInputRef.current) nameInputRef.current.value = result.name;
                    if (result.dose && doseInputRef.current) doseInputRef.current.value = result.dose;
                    if (result.form && formInputRef.current) formInputRef.current.value = result.form;
                    if (result.route && routeInputRef.current) routeInputRef.current.value = result.route;
                    if (result.frequency && freqInputRef.current) {
                        freqInputRef.current.value = result.frequency;
                        setFormFrequency(result.frequency as FrequencyType);
                    }
                    if (result.intervalHours && intervalInputRef.current) intervalInputRef.current.value = String(result.intervalHours);
                    if (result.notes && notesInputRef.current) notesInputRef.current.value = result.notes;
                } catch (e) {
                    alert("Failed to process audio.");
                } finally {
                    setIsProcessingAudio(false);
                    setIsRecording(false);
                    stream.getTracks().forEach(track => track.stop());
                }
            };
        };
        recorder.start();
        setIsRecording(true);
    } catch (err) {
        alert("Microphone access denied.");
    }
  };

  const stopRecording = () => {
      if (mediaRecorderRef.current && isRecording) {
          mediaRecorderRef.current.stop();
      }
  };

  const exportData = () => {
    const headers = ["Date", "Time", "Patient", "Room", "Medication", "Dose", "Route", "Frequency", "Status", "Nurse", "Notes"];
    const csvRows = [headers.join(",")];

    for (const p of patients) {
      const pMeds = medications.filter(m => m.patientId === p.id);
      for (const m of pMeds) {
          const medLogs = logs.filter(l => l.medicationId === m.id).sort((a, b) => a.servedAt - b.servedAt);

          if (medLogs.length === 0) {
              // No logs yet - export the setup
              csvRows.push([
                  `"-"`,`"-"`,
                  `"${p.name}"`,`"${p.roomNumber || ''}"`,
                  `"${m.name}"`,`"${m.dose}"`,`"${m.route}"`,`"${m.frequency}"`,
                  `"${m.isCompleted ? 'COMPLETED' : 'ACTIVE'}"`,
                  `"-"`,
                  `"${m.notes || ''}"`
              ].join(","));
          } else {
              // Export logs
              for (const log of medLogs) {
                  const d = new Date(log.servedAt);
                  const dateStr = d.toLocaleDateString();
                  const timeStr = d.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'});

                  // Combine notes: Med notes (instructions) + Log notes (event comments)
                  let combinedNotes = m.notes ? `[Instr: ${m.notes}] ` : "";
                  if (log.notes) combinedNotes += `[Log: ${log.notes}]`;

                  csvRows.push([
                      `"${dateStr}"`,`"${timeStr}"`,
                      `"${p.name}"`,`"${p.roomNumber || ''}"`,
                      `"${m.name}"`,`"${m.dose}"`,`"${m.route}"`,`"${m.frequency}"`,
                      `"${log.status}"`,
                      `"${log.nurseName || 'Unknown'}"`,
                      `"${combinedNotes.trim()}"`
                  ].join(","));
              }
          }
      }
    }

    const blob = new Blob([csvRows.join("\n")], { type: "text/csv" });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `nurseflow_export_${new Date().toISOString().slice(0,10)}.csv`;
    a.click();
  };

  // --- DERIVED STATE ---

  const upcomingDoses = useMemo(() => {
    const sorted = medications
      .filter(m => m.nextDueAt !== null && m.frequency !== FrequencyType.PRN && !m.isCompleted)
      .map(m => {
        const patient = patients.find(p => p.id === m.patientId);
        return { ...m, patientName: patient?.name || 'Unknown', patientRoom: patient?.roomNumber };
      });
    sorted.sort((a, b) => {
        if (dashboardSort === 'TIME') return (a.nextDueAt || 0) - (b.nextDueAt || 0);
        if (dashboardSort === 'PATIENT') return a.patientName.localeCompare(b.patientName);
        if (dashboardSort === 'MEDICATION') return a.name.localeCompare(b.name);
        return 0;
    });
    return sorted;
  }, [medications, patients, dashboardSort]);

  const selectedPatient = patients.find(p => p.id === selectedPatientId);
  const activeMeds = medications.filter(m => m.patientId === selectedPatientId && !m.isCompleted);
  const completedMeds = medications.filter(m => m.patientId === selectedPatientId && m.isCompleted);

  // --- VIEWS ---

  if (!currentUser) {
    return (
        <div className="min-h-screen bg-slate-100 dark:bg-slate-900 flex flex-col items-center justify-center p-6 transition-colors">
            <div className="w-full max-w-md">
                <div className="flex flex-col items-center mb-10">
                    <div className="bg-teal-600 p-4 rounded-2xl shadow-xl mb-4">
                        <HeartPulse className="w-10 h-10 text-white" />
                    </div>
                    <h1 className="text-3xl font-bold text-slate-800 dark:text-white tracking-tight">NurseFlow</h1>
                    <p className="text-slate-500 dark:text-slate-400 text-sm mt-2">Shared Medication Management System</p>
                </div>

                <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-lg border border-slate-200 dark:border-slate-700 p-6">
                    <h2 className="text-xl font-bold text-slate-800 dark:text-white mb-6 flex items-center gap-2">
                        <User className="w-5 h-5 text-teal-600 dark:text-teal-400" />
                        Who is signing in?
                    </h2>

                    <div className="grid grid-cols-2 gap-4">
                        {nurses.map(nurse => (
                            <button
                                key={nurse.id}
                                onClick={() => setCurrentUser(nurse)}
                                className="flex flex-col items-center p-4 rounded-xl border border-slate-100 dark:border-slate-700 hover:border-teal-400 hover:bg-teal-50 dark:hover:bg-teal-900/20 transition-all active:scale-95 bg-slate-50 dark:bg-slate-700/50"
                            >
                                <div className={`w-12 h-12 rounded-full flex items-center justify-center font-bold text-lg mb-2 shadow-sm ${nurse.color || 'bg-slate-200'}`}>
                                    {nurse.initials}
                                </div>
                                <span className="font-bold text-slate-700 dark:text-slate-200 text-sm truncate w-full text-center">{nurse.name}</span>
                                <span className="text-xs text-slate-400 font-medium">{nurse.designation}</span>
                            </button>
                        ))}

                        <button
                            onClick={() => {
                                setEditingPatient(null); // Clear potential trash
                                setIsCreateProfileOpen(true);
                            }}
                            className="flex flex-col items-center justify-center p-4 rounded-xl border border-dashed border-slate-300 dark:border-slate-600 hover:border-teal-400 hover:bg-white dark:hover:bg-slate-800 text-slate-400 dark:text-slate-500 hover:text-teal-600 transition-all active:scale-95"
                        >
                            <div className="w-12 h-12 rounded-full bg-white dark:bg-slate-700 border border-slate-200 dark:border-slate-600 flex items-center justify-center mb-2">
                                <Plus className="w-6 h-6" />
                            </div>
                            <span className="font-bold text-sm">New Profile</span>
                            <span className="text-xs opacity-0">.</span>
                        </button>
                    </div>
                </div>
            </div>

            {/* Create Profile Modal */}
            <Modal
                isOpen={isCreateProfileOpen}
                onClose={() => setIsCreateProfileOpen(false)}
                title="Create New Profile"
            >
                <form onSubmit={handleCreateNurse} className="space-y-4">
                     <div>
                        <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-1">Full Name</label>
                        <input name="name" required className="w-full p-3 bg-slate-50 dark:bg-slate-700 dark:border-slate-600 border rounded-xl outline-none focus:ring-2 focus:ring-teal-500 text-slate-900 dark:text-white" placeholder="e.g. Sarah Jenkins" />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-1">Initials</label>
                            <input name="initials" required maxLength={3} className="w-full p-3 bg-slate-50 dark:bg-slate-700 dark:border-slate-600 border rounded-xl outline-none focus:ring-2 focus:ring-teal-500 uppercase text-slate-900 dark:text-white" placeholder="SJ" />
                        </div>
                        <div>
                            <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-1">Designation</label>
                            <select name="designation" className="w-full p-3 bg-slate-50 dark:bg-slate-700 dark:border-slate-600 border rounded-xl outline-none focus:ring-2 focus:ring-teal-500 text-slate-900 dark:text-white">
                                <option value="RN">RN</option>
                                <option value="LPN">LPN</option>
                                <option value="CNA">CNA</option>
                                <option value="Student">Student</option>
                                <option value="NP">NP</option>
                            </select>
                        </div>
                    </div>
                    <button type="submit" className="w-full bg-teal-600 text-white font-bold py-3 rounded-xl mt-4 hover:bg-teal-700">Create Profile</button>
                </form>
            </Modal>
        </div>
    );
  }

  const renderDashboard = () => (
    <div className="space-y-4 pb-24 md:pb-10 h-full">
      <header className="px-4 md:px-8 pt-6 pb-2 flex justify-between items-center">
        <div>
           <h1 className="text-3xl font-bold text-slate-800 dark:text-white">Upcoming</h1>
           <p className="text-slate-500 dark:text-slate-400">{new Date().toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric'})}</p>
        </div>
      </header>

      {/* Sorting Controls */}
      <div className="px-4 md:px-8 flex items-center gap-2 overflow-x-auto no-scrollbar">
         <span className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase mr-1">Sort By:</span>
         <button 
            onClick={() => setDashboardSort('TIME')}
            className={`px-3 py-1.5 rounded-full text-xs font-bold whitespace-nowrap transition-colors ${
                dashboardSort === 'TIME' ? 'bg-teal-600 text-white shadow-md' : 'bg-white dark:bg-slate-800 text-slate-500 dark:text-slate-400 border border-slate-200 dark:border-slate-700'
            }`}
         >
            <Clock className="w-3 h-3 inline mr-1" /> Time
         </button>
         <button 
            onClick={() => setDashboardSort('PATIENT')}
            className={`px-3 py-1.5 rounded-full text-xs font-bold whitespace-nowrap transition-colors ${
                dashboardSort === 'PATIENT' ? 'bg-teal-600 text-white shadow-md' : 'bg-white dark:bg-slate-800 text-slate-500 dark:text-slate-400 border border-slate-200 dark:border-slate-700'
            }`}
         >
            <Users className="w-3 h-3 inline mr-1" /> Patient
         </button>
         <button 
            onClick={() => setDashboardSort('MEDICATION')}
            className={`px-3 py-1.5 rounded-full text-xs font-bold whitespace-nowrap transition-colors ${
                dashboardSort === 'MEDICATION' ? 'bg-teal-600 text-white shadow-md' : 'bg-white dark:bg-slate-800 text-slate-500 dark:text-slate-400 border border-slate-200 dark:border-slate-700'
            }`}
         >
            <Pill className="w-3 h-3 inline mr-1" /> Med Name
         </button>
      </div>

      {/* Grid Content */}
      <div className="px-4 md:px-8">
        {upcomingDoses.length === 0 ? (
            <div className="p-8 bg-white dark:bg-slate-800 rounded-2xl text-center shadow-sm border border-slate-100 dark:border-slate-700 mt-4 max-w-md mx-auto md:max-w-none">
            <EmptyDashboardGraphic />
            <h3 className="text-lg font-medium text-slate-800 dark:text-white">All Caught Up</h3>
            <p className="text-slate-400">No scheduled doses pending.</p>
            </div>
        ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4 mt-2">
            {upcomingDoses.map(med => {
                const isStat = med.frequency === FrequencyType.STAT;
                const status = isStat ? 'stat' : getRelativeTimeStatus(med.nextDueAt!);
                let statusColor = "bg-teal-50 border-teal-200 dark:bg-teal-900/20 dark:border-teal-900";
                let textColor = "text-teal-900 dark:text-teal-200";
                let timeColor = "text-teal-700 dark:text-teal-300";

                if (status === 'overdue') {
                statusColor = "bg-red-50 border-red-200 dark:bg-red-900/20 dark:border-red-900 animate-pulse";
                textColor = "text-red-900 dark:text-red-200";
                timeColor = "text-red-700 dark:text-red-300";
                } else if (status === 'stat') {
                statusColor = "bg-rose-50 border-rose-200 dark:bg-rose-900/20 dark:border-rose-900";
                textColor = "text-rose-900 dark:text-rose-200";
                timeColor = "text-rose-700 dark:text-rose-300";
                } else if (status === 'soon') {
                statusColor = "bg-amber-50 border-amber-200 dark:bg-amber-900/20 dark:border-amber-900";
                textColor = "text-amber-900 dark:text-amber-200";
                timeColor = "text-amber-700 dark:text-amber-300";
                }

                return (
                <div key={med.id} className={`p-4 rounded-xl border ${statusColor} shadow-sm flex justify-between items-center`}>
                    <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1">
                        {isStat ? (
                            <span className={`text-xs font-bold uppercase tracking-wider px-2 py-0.5 rounded-full bg-white/50 dark:bg-black/20 flex items-center gap-1 ${timeColor}`}>
                                <Zap className="w-3 h-3 fill-current" /> STAT
                            </span>
                        ) : (
                            <span className={`text-xs font-bold uppercase tracking-wider px-2 py-0.5 rounded-full bg-white/50 dark:bg-black/20 ${timeColor}`}>
                                {status === 'overdue' ? 'OVERDUE' : formatTime(med.nextDueAt!)}
                            </span>
                        )}
                        <span className="text-xs text-slate-500 dark:text-slate-400 font-medium truncate">{med.patientName}</span>
                    </div>
                    <h3 className={`text-lg font-bold ${textColor} truncate`}>{med.name}</h3>
                    <p className={`text-sm opacity-80 ${textColor} truncate`}>
                        {med.dose} • {med.form ? `${med.form} • ` : ''}{med.route}
                    </p>
                    {med.notes && (
                        <div className="flex items-center gap-1 mt-1.5 text-xs text-slate-500 dark:text-slate-400 italic">
                            <StickyNote className="w-3 h-3 flex-shrink-0" />
                            <span className="truncate">{med.notes}</span>
                        </div>
                    )}
                    </div>
