                    <button onClick={() => setConfirmConfig(prev => ({ ...prev, isOpen: false }))} className="w-full py-3 rounded-xl font-bold text-slate-600 dark:text-slate-300 bg-slate-100 dark:bg-slate-700 hover:bg-slate-200 dark:hover:bg-slate-600 transition-colors">Cancel</button>
                    <button onClick={confirmConfig.onConfirm} className="w-full py-3 rounded-xl font-bold text-white bg-red-600 hover:bg-red-700 shadow-md transition-colors">Confirm</button>
                </div>
            </div>
        </Modal>

      </main>
    </div>
  );
}

