  const exportData = () => {
    const headers = ["Date", "Time", "Patient", "Room", "Medication", "Dose", "Route", "Frequency", "Status", "Nurse", "Notes"];
    const csvRows = [headers.join(",")];

    for (const p of patients) {
      const pMeds = medications.filter(m => m.patientId === p.id);
      for (const m of pMeds) {
          const medLogs = logs.filter(l => l.medicationId === m.id).sort((a, b) => a.servedAt - b.servedAt);

          if (medLogs.length === 0) {
              // No logs yet - export the setup
              csvRows.push([
                  `"-"`,`"-"`,
                  `"${p.name}"`,`"${p.roomNumber || ''}"`,
                  `"${m.name}"`,`"${m.dose}"`,`"${m.route}"`,`"${m.frequency}"`,
                  `"${m.isCompleted ? 'COMPLETED' : 'ACTIVE'}"`,
                  `"-"`,
                  `"${m.notes || ''}"`
              ].join(","));
          } else {
              // Export logs
              for (const log of medLogs) {
                  const d = new Date(log.servedAt);
                  const dateStr = d.toLocaleDateString();
                  const timeStr = d.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'});

                  // Combine notes: Med notes (instructions) + Log notes (event comments)
                  let combinedNotes = m.notes ? `[Instr: ${m.notes}] ` : "";
                  if (log.notes) combinedNotes += `[Log: ${log.notes}]`;

                  csvRows.push([
                      `"${dateStr}"`,`"${timeStr}"`,
                      `"${p.name}"`,`"${p.roomNumber || ''}"`,
                      `"${m.name}"`,`"${m.dose}"`,`"${m.route}"`,`"${m.frequency}"`,
                      `"${log.status}"`,
                      `"${log.nurseName || 'Unknown'}"`,
                      `"${combinedNotes.trim()}"`
                  ].join(","));
              }
          }
      }
    }

    const blob = new Blob([csvRows.join("\n")], { type: "text/csv" });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `nurseflow_export_${new Date().toISOString().slice(0,10)}.csv`;
