const AiResponseDisplay = ({ text }: { text: string }) => {
  if (!text) return null;

  const lines = text.replace(/\r\n/g, '\n').split('\n');
  const elements: React.ReactNode[] = [];
  let listBuffer: React.ReactNode[] = [];

  const flushList = () => {
    if (listBuffer.length > 0) {
      elements.push(
        <ul key={`list-${elements.length}`} className="list-disc pl-5 mb-2 space-y-1">
          {listBuffer}
        </ul>
      );
      listBuffer = [];
    }
  };

  const parseLine = (str: string) => {
    const parts = str.split(/(\*\*.*?\*\*)/g);
    return parts.map((part, i) => {
      if (part.startsWith('**') && part.endsWith('**')) {
        return <strong key={i} className="font-bold text-indigo-950 dark:text-indigo-200">{part.slice(2, -2)}</strong>;
      }
      return part;
    });
  };

  lines.forEach((line, i) => {
    const trim = line.trim();
    if (!trim) {
      flushList();
      return;
    }

    if (trim.startsWith('* ') || trim.startsWith('- ') || trim.startsWith('• ')) {
      const content = trim.replace(/^[\*\-\•]\s*/, '');
      listBuffer.push(<li key={`li-${i}`}>{parseLine(content)}</li>);
    } else {
      flushList();
      if (trim.startsWith('### ')) {
        elements.push(<h4 key={`h4-${i}`} className="font-bold text-sm uppercase tracking-wide mt-3 mb-1 text-indigo-800 dark:text-indigo-300">{parseLine(trim.substring(4))}</h4>);
      } else if (trim.startsWith('## ')) {
        elements.push(<h3 key={`h3-${i}`} className="font-bold text-base mt-4 mb-2 text-indigo-900 dark:text-indigo-100">{parseLine(trim.substring(3))}</h3>);
      } else {
        elements.push(<p key={`p-${i}`} className="mb-2 last:mb-0">{parseLine(trim)}</p>);
      }
    }
  });
  flushList();

  return (
    <div className="mt-4 p-4 bg-indigo-50 dark:bg-indigo-950/40 rounded-xl border border-indigo-100 dark:border-indigo-900 text-sm text-indigo-900 dark:text-indigo-200 leading-relaxed animate-in fade-in slide-in-from-top-2 duration-300">
      <div className="flex items-center gap-2 mb-3 border-b border-indigo-200 dark:border-indigo-800 pb-2">
         <BrainCircuit className="w-4 h-4 text-indigo-600 dark:text-indigo-400" />
         <span className="font-bold text-indigo-700 dark:text-indigo-300 text-xs uppercase tracking-wider">AI Assistant Response</span>
      </div>
      <div className="space-y-1">
         {elements}
      </div>
    </div>
  );
};

// --- MAIN APP COMPONENT ---

export default function App() {
  // --- STATE ---

  const [nurses, setNurses] = useState<Nurse[]>(() => {
    const saved = localStorage.getItem('nurses');
    return saved ? JSON.parse(saved) : [];
  });

  const [currentUser, setCurrentUser] = useState<Nurse | null>(() => {
    const savedId = localStorage.getItem('currentUserId');
    const savedNurses = localStorage.getItem('nurses');
    const nursesList: Nurse[] = savedNurses ? JSON.parse(savedNurses) : [];
    if (savedId && nursesList.length > 0) {
        return nursesList.find(n => n.id === savedId) || null;
    }
    return null;
  });

  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem('darkMode');
    return saved ? JSON.parse(saved) : false;
  });

  const [view, setView] = useState<ViewState>('DASHBOARD');
  const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
  const [patients, setPatients] = useState<Patient[]>(() => {
    const saved = localStorage.getItem('patients');
    return saved ? JSON.parse(saved) : [];
  });
  const [medications, setMedications] = useState<Medication[]>(() => {
    const saved = localStorage.getItem('medications');
    return saved ? JSON.parse(saved) : [];
  });
  const [logs, setLogs] = useState<MedicationLog[]>(() => {
    const saved = localStorage.getItem('logs');
    return saved ? JSON.parse(saved) : [];
  });

  const [isAddPatientOpen, setIsAddPatientOpen] = useState(false);
  const [editingPatient, setEditingPatient] = useState<Patient | null>(null);
  const [isAddMedOpen, setIsAddMedOpen] = useState(false);
  const [editingMed, setEditingMed] = useState<Medication | null>(null);
  const [formFrequency, setFormFrequency] = useState<FrequencyType>(FrequencyType.STAT); 
  const [loggingMed, setLoggingMed] = useState<Medication | null>(null);
  const [expandedHistoryMedId, setExpandedHistoryMedId] = useState<string | null>(null);
  const [aiQuery, setAiQuery] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [dashboardSort, setDashboardSort] = useState<'TIME' | 'PATIENT' | 'MEDICATION'>('TIME');
  const [isCreateProfileOpen, setIsCreateProfileOpen] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isProcessingAudio, setIsProcessingAudio] = useState(false);
  const [selectedMedIds, setSelectedMedIds] = useState<Set<string>>(new Set());
  const [drugInfoModal, setDrugInfoModal] = useState({ isOpen: false, medName: '', loading: false, content: '' });
  const [notificationPermission, setNotificationPermission] = useState<NotificationPermission>('default');
  const [alertedDoses, setAlertedDoses] = useState<Set<string>>(() => new Set());
  const [confirmConfig, setConfirmConfig] = useState({ isOpen: false, title: '', message: '', onConfirm: () => {} });

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const nameInputRef = useRef<HTMLInputElement>(null);
  const doseInputRef = useRef<HTMLInputElement>(null);
  const formInputRef = useRef<HTMLSelectElement>(null);
  const routeInputRef = useRef<HTMLSelectElement>(null);
  const freqInputRef = useRef<HTMLSelectElement>(null);
  const intervalInputRef = useRef<HTMLInputElement>(null);
  const notesInputRef = useRef<HTMLTextAreaElement>(null);

  // --- EFFECTS ---

  useEffect(() => {
    localStorage.setItem('darkMode', JSON.stringify(isDarkMode));
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  useEffect(() => localStorage.setItem('patients', JSON.stringify(patients)), [patients]);
  useEffect(() => localStorage.setItem('medications', JSON.stringify(medications)), [medications]);
  useEffect(() => localStorage.setItem('logs', JSON.stringify(logs)), [logs]);
  useEffect(() => localStorage.setItem('nurses', JSON.stringify(nurses)), [nurses]);
  useEffect(() => {
    if (currentUser) localStorage.setItem('currentUserId', currentUser.id);
    else localStorage.removeItem('currentUserId');
  }, [currentUser]);

  useEffect(() => { setSelectedMedIds(new Set()); }, [selectedPatientId, view]);

  useEffect(() => {
    if ('Notification' in window) setNotificationPermission(Notification.permission);
  }, []);

  useEffect(() => {
    if (notificationPermission !== 'granted') return;
    const checkDoses = () => {
      const now = Date.now();
      medications.forEach(med => {
        if (!med.nextDueAt || med.frequency === FrequencyType.PRN || med.isCompleted) return;
        const isDue = med.nextDueAt <= now;
        const isReasonablyRecent = (now - med.nextDueAt) < (24 * 60 * 60 * 1000); 
        if (isDue && isReasonablyRecent) {
          const alertKey = `${med.id}_${med.nextDueAt}`;
          if (!alertedDoses.has(alertKey)) {
            const patient = patients.find(p => p.id === med.patientId);
            const patientName = patient ? patient.name : 'Unknown Patient';
            try {
                new Notification(`Medication Due: ${med.name}`, {
                  body: `${patientName} - ${med.dose} ${med.route}\nDue at ${formatTime(med.nextDueAt)}`,
                  tag: alertKey
                });
            } catch (e) { console.error("Failed to fire notification", e); }
            setAlertedDoses(prev => new Set(prev).add(alertKey));
          }
        }
      });
    };
    const intervalId = setInterval(checkDoses, 30000); 
    checkDoses(); 
    return () => clearInterval(intervalId);
  }, [medications, patients, notificationPermission, alertedDoses]);

  // --- ACTIONS ---

  const handleCreateNurse = (e: React.FormEvent<HTMLFormElement>) => {
      e.preventDefault();
      const fd = new FormData(e.currentTarget);
      const name = fd.get('name') as string;
      const initials = fd.get('initials') as string;
      const designation = fd.get('designation') as string;
      const color = AVATAR_COLORS[Math.floor(Math.random() * AVATAR_COLORS.length)];
      const newNurse: Nurse = { id: generateId(), name, initials: initials.toUpperCase(), designation, color };
      setNurses(prev => [...prev, newNurse]);
      setCurrentUser(newNurse);
      setIsCreateProfileOpen(false);
  };

  const handleUpdateNurse = (e: React.FormEvent<HTMLFormElement>) => {
      e.preventDefault();
      if (!currentUser) return;
      const fd = new FormData(e.currentTarget);
      const updatedNurse = {
          ...currentUser,
          name: fd.get('name') as string,
          initials: (fd.get('initials') as string).toUpperCase(),
          designation: fd.get('designation') as string,
      };
      setNurses(prev => prev.map(n => n.id === currentUser.id ? updatedNurse : n));
      setCurrentUser(updatedNurse);
      setIsCreateProfileOpen(false);
  };

  const addPatient = (name: string, roomNumber: string) => {
    const newPatient: Patient = { id: generateId(), name, roomNumber };
    setPatients(prev => [...prev, newPatient]);
    setIsAddPatientOpen(false);
  };

  const updatePatient = (id: string, name: string, roomNumber: string) => {
    setPatients(prev => prev.map(p => p.id === id ? { ...p, name, roomNumber } : p));
    setIsAddPatientOpen(false);
    setEditingPatient(null);
  };

  const deletePatient = (id: string) => {
    setConfirmConfig({
        isOpen: true,
        title: 'Delete Patient?',
        message: 'Permanently remove the patient and records?',
        onConfirm: () => {
            setPatients(prev => prev.filter(p => p.id !== id));
            setMedications(prev => prev.filter(m => m.patientId !== id));
            setView('PATIENTS');
            setConfirmConfig(prev => ({ ...prev, isOpen: false }));
        }
    });
  };

  const addMedication = (med: Omit<Medication, 'id' | 'lastServedAt' | 'nextDueAt' | 'isCompleted'>) => {
    const newMed: Medication = {
      ...med,
      id: generateId(),
      lastServedAt: null,
      nextDueAt: med.frequency === FrequencyType.STAT ? Date.now() : null, 
      isCompleted: false
    };
    setMedications(prev => [...prev, newMed]);
    setIsAddMedOpen(false);
  };

  const updateMedication = (id: string, updates: Partial<Medication>) => {
    setMedications(prev => prev.map(m => {
        if (m.id !== id) return m;
        const updatedMed = { ...m, ...updates };
        if (updates.frequency === FrequencyType.STAT && m.frequency !== FrequencyType.STAT) updatedMed.nextDueAt = Date.now();
        if (updates.intervalHours !== undefined && updates.intervalHours !== m.intervalHours) {
            if (updatedMed.frequency !== FrequencyType.STAT && updatedMed.frequency !== FrequencyType.PRN && m.lastServedAt) {
                 updatedMed.nextDueAt = m.lastServedAt + (updatedMed.intervalHours * 3600000);
            } else if (updatedMed.frequency === FrequencyType.PRN) updatedMed.nextDueAt = null;
        }
        return updatedMed;
    }));
    setIsAddMedOpen(false);
    setEditingMed(null);
  };

  const toggleMedicationComplete = (medId: string) => {
    setMedications(prev => prev.map(m => {
        if (m.id !== medId) return m;
        const isNowCompleted = !m.isCompleted;
        return { ...m, isCompleted: isNowCompleted, nextDueAt: isNowCompleted ? null : Date.now() };
    }));
  };

  const handleManualLog = (medId: string, status: LogStatus, timestamp: number, notes?: string) => {
    const med = medications.find(m => m.id === medId);
    if (!med || !currentUser) return;

    let nextDue: number | null = med.nextDueAt;
    let isNowCompleted = med.isCompleted;

    if (med.frequency === FrequencyType.STAT) {
        nextDue = null;
        isNowCompleted = true; 
    } else if (med.frequency !== FrequencyType.PRN) {
        if (status === 'SERVED') nextDue = timestamp + (med.intervalHours * 60 * 60 * 1000);
        else if (status === 'MISSED') {
            nextDue = (med.nextDueAt || timestamp) + (med.intervalHours * 60 * 60 * 1000);
        }
    }

    setMedications(prev => prev.map(m => m.id === medId ? { ...m, lastServedAt: status === 'SERVED' ? timestamp : m.lastServedAt, nextDueAt: nextDue, isCompleted: isNowCompleted } : m));
    setLogs(prev => [...prev, { id: generateId(), medicationId: medId, servedAt: timestamp, status, notes, nurseId: currentUser.id, nurseName: currentUser.name, nurseInitials: currentUser.initials, nurseColor: currentUser.color }]);
    setLoggingMed(null);
  };

  const handleAskAi = async () => {
    if (!aiQuery.trim()) return;
    setIsAiLoading(true);
    const answer = await askDrugInfo(aiQuery);
    setAiResponse(answer);
    setIsAiLoading(false);
  };

  const exportData = () => {
    const headers = ["Date", "Time", "Patient", "Room", "Medication", "Dose", "Route", "Frequency", "Status", "Nurse", "Notes"];
    const csvRows = [headers.join(",")];
    for (const p of patients) {
      const pMeds = medications.filter(m => m.patientId === p.id);
      for (const m of pMeds) {
          const medLogs = logs.filter(l => l.medicationId === m.id).sort((a, b) => a.servedAt - b.servedAt);
          if (medLogs.length === 0) {
              csvRows.push([`"-"`,`"-"`,`"${p.name}"`,`"${p.roomNumber || ''}"`,`"${m.name}"`,`"${m.dose}"`,`"${m.route}"`,`"${m.frequency}"`,`"${m.isCompleted ? 'COMPLETED' : 'ACTIVE'}"`,`"-"`,`"${m.notes || ''}"`].join(","));
          } else {
              for (const log of medLogs) {
                  const d = new Date(log.servedAt);
                  let combinedNotes = m.notes ? `[Instr: ${m.notes}] ` : "";
                  if (log.notes) combinedNotes += `[Log: ${log.notes}]`;
                  csvRows.push([`"${d.toLocaleDateString()}"`,`"${d.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}"`,`"${p.name}"`,`"${p.roomNumber || ''}"`,`"${m.name}"`,`"${m.dose}"`,`"${m.route}"`,`"${m.frequency}"`,`"${log.status}"`,`"${log.nurseName || 'Unknown'}"`,`"${combinedNotes.trim()}"`].join(","));
              }
          }
      }
    }
    const blob = new Blob([csvRows.join("\n")], { type: "text/csv" });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `nurseflow_export_${new Date().toISOString().slice(0,10)}.csv`;
    a.click();
  };

  // --- DERIVED STATE ---

  const upcomingDoses = useMemo(() => {
    const sorted = medications
      .filter(m => m.nextDueAt !== null && m.frequency !== FrequencyType.PRN && !m.isCompleted)
      .map(m => {
        const patient = patients.find(p => p.id === m.patientId);
        return { ...m, patientName: patient?.name || 'Unknown', patientRoom: patient?.roomNumber };
      });
    sorted.sort((a, b) => {
        if (dashboardSort === 'TIME') return (a.nextDueAt || 0) - (b.nextDueAt || 0);
        if (dashboardSort === 'PATIENT') return a.patientName.localeCompare(b.patientName);
        if (dashboardSort === 'MEDICATION') return a.name.localeCompare(b.name);
        return 0;
    });
    return sorted;
  }, [medications, patients, dashboardSort]);

  const selectedPatient = patients.find(p => p.id === selectedPatientId);
  const activeMeds = medications.filter(m => m.patientId === selectedPatientId && !m.isCompleted);
  const completedMeds = medications.filter(m => m.patientId === selectedPatientId && m.isCompleted);

