      <header className="px-4 md:px-8 pt-6 pb-2 flex justify-between items-center">
        <div>
           <h1 className="text-3xl font-bold text-slate-800 dark:text-white">Upcoming</h1>
           <p className="text-slate-500 dark:text-slate-400">{new Date().toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric'})}</p>
        </div>
      </header>
      <div className="px-4 md:px-8 flex items-center gap-2 overflow-x-auto no-scrollbar">
         <button onClick={() => setDashboardSort('TIME')} className={`px-3 py-1.5 rounded-full text-xs font-bold whitespace-nowrap ${dashboardSort === 'TIME' ? 'bg-teal-600 text-white' : 'bg-white dark:bg-slate-800 text-slate-500 border border-slate-200 dark:border-slate-700'}`}>Time</button>
         <button onClick={() => setDashboardSort('PATIENT')} className={`px-3 py-1.5 rounded-full text-xs font-bold whitespace-nowrap ${dashboardSort === 'PATIENT' ? 'bg-teal-600 text-white' : 'bg-white dark:bg-slate-800 text-slate-500 border border-slate-200 dark:border-slate-700'}`}>Patient</button>
      </div>
      <div className="px-4 md:px-8">
        {upcomingDoses.length === 0 ? (
            <div className="p-8 bg-white dark:bg-slate-800 rounded-2xl text-center shadow-sm border border-slate-100 dark:border-slate-700 mt-4 max-w-md mx-auto">
            <EmptyDashboardGraphic />
            <h3 className="text-lg font-medium text-slate-800 dark:text-white">All Caught Up</h3>
            </div>
        ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4 mt-2">
            {upcomingDoses.map(med => (
                <div key={med.id} className="p-4 rounded-xl border bg-white dark:bg-slate-800 shadow-sm flex justify-between items-center">
                    <div className="flex-1 min-w-0">
