                    <button onClick={() => handleManualLog(med.id, 'SERVED', Date.now())} className="ml-3 p-3 bg-teal-50 dark:bg-teal-900/30 rounded-full">
                        <Check className="w-6 h-6 text-teal-600" />
                    </button>
                </div>
