        <h1 className="text-3xl font-bold text-slate-800 dark:text-white">Patients</h1>
        <button onClick={() => { setEditingPatient(null); setIsAddPatientOpen(true); }} className="bg-teal-600 text-white px-4 py-2 rounded-xl shadow-lg flex items-center gap-2"><Plus className="w-6 h-6" />Add Patient</button>
      </header>
      <div className="px-4 md:px-8 grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
        {patients.map(patient => (
            <div key={patient.id} onClick={() => { setSelectedPatientId(patient.id); setView('PATIENT_DETAIL'); }} className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 cursor-pointer">
              <h3 className="text-lg font-bold text-slate-800 dark:text-white">{patient.name}</h3>
              <p className="text-sm text-slate-500">Room {patient.roomNumber || "N/A"}</p>
            </div>
        ))}
      </div>
    </div>
  );

  const renderPatientDetail = () => (
    <div className="space-y-4 px-4 md:px-8 pt-6 pb-24 h-full">
        <button onClick={() => setView('PATIENTS')} className="flex items-center gap-1 text-slate-500 mb-2"><ChevronLeft className="w-5 h-5" /> Back</button>
        <h1 className="text-3xl font-bold text-slate-800 dark:text-white">{selectedPatient?.name}</h1>
        <button onClick={() => setIsAddMedOpen(true)} className="w-full md:w-auto px-8 bg-teal-600 text-white py-3 rounded-xl font-bold"><Plus className="w-5 h-5 inline mr-1" /> Add Medication</button>
        <div className="grid grid-cols-1 gap-4 mt-4">
            {activeMeds.map(med => (
                <div key={med.id} className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-100 shadow-sm">
                    <h3 className="text-lg font-bold text-slate-800 dark:text-white">{med.name}</h3>
                    <p className="text-sm text-slate-500">{med.dose} • {med.route}</p>
                    <div className="mt-3 flex justify-between items-center">
                        <span className="text-xs font-bold text-teal-600 uppercase">Next: {med.nextDueAt ? formatTime(med.nextDueAt) : "N/A"}</span>
                        <button onClick={() => setLoggingMed(med)} className="text-xs bg-slate-100 dark:bg-slate-700 px-3 py-1.5 rounded-lg font-bold">Log Dose</button>
                    </div>
                </div>
            ))}
        </div>
    </div>
  );

  const renderSettings = () => (
    <div className="pb-24 px-4 md:px-8 pt-6 space-y-6">
        <h1 className="text-3xl font-bold text-slate-800 dark:text-white">Settings</h1>
        <div className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
             <div className="flex items-center gap-4 mb-3">
                 <div className={`w-14 h-14 rounded-full flex items-center justify-center font-bold text-xl ${currentUser?.color || 'bg-slate-200'}`}>{currentUser?.initials}</div>
                 <div>
                     <h2 className="font-bold text-lg text-slate-800 dark:text-white">{currentUser?.name}</h2>
                     <p className="text-slate-500 text-sm">{currentUser?.designation}</p>
                 </div>
             </div>
             <button onClick={() => setCurrentUser(null)} className="w-full py-2 flex items-center justify-center gap-2 text-red-600 font-bold border border-red-100 rounded-lg">Sign Out</button>
        </div>
        <button onClick={exportData} className="w-full py-3 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-300 rounded-xl font-bold flex items-center justify-center gap-2"><Download className="w-5 h-5" />Export Data (CSV)</button>
    </div>
  );

  // --- MAIN RENDER ---

  if (!currentUser) {
    return (
        <div className="min-h-screen bg-slate-100 dark:bg-slate-900 flex flex-col items-center justify-center p-6">
            <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-lg border border-slate-200 dark:border-slate-700 p-6 w-full max-w-md">
                <h2 className="text-xl font-bold mb-6 text-slate-800 dark:text-white flex items-center gap-2"><User className="w-5 h-5 text-teal-600" /> Sign In</h2>
                <div className="grid grid-cols-2 gap-4">
                    {nurses.map(nurse => (
