                            <div className={`w-12 h-12 rounded-full flex items-center justify-center font-bold mb-2 ${nurse.color || 'bg-slate-200'}`}>{nurse.initials}</div>
                            <span className="font-bold text-sm text-slate-700 dark:text-slate-200">{nurse.name}</span>
                        </button>
                    ))}
                    <button onClick={() => setIsCreateProfileOpen(true)} className="flex flex-col items-center justify-center p-4 rounded-xl border border-dashed border-slate-300 text-slate-400">
                        <Plus className="w-6 h-6 mb-2" />
                        <span className="font-bold text-sm">New Profile</span>
                    </button>
                </div>
            </div>
            <Modal isOpen={isCreateProfileOpen} onClose={() => setIsCreateProfileOpen(false)} title="Create New Profile">
                <form onSubmit={handleCreateNurse} className="space-y-4">
                    <input name="name" required className="w-full p-3 bg-slate-50 dark:bg-slate-700 border rounded-xl" placeholder="Full Name" />
