const AiResponseDisplay = ({ text }: { text: string }) => {
  if (!text) return null;
  const lines = text.replace(/\r\n/g, '\n').split('\n');
  const elements: React.ReactNode[] = [];
  let listBuffer: React.ReactNode[] = [];
  const flushList = () => {
    if (listBuffer.length > 0) {
      elements.push(<ul key={`list-${elements.length}`} className="list-disc pl-5 mb-2 space-y-1">{listBuffer}</ul>);
      listBuffer = [];
    }
  };
  const parseLine = (str: string) => {
    const parts = str.split(/(\*\*.*?\*\*)/g);
    return parts.map((part, i) => {
      if (part.startsWith('**') && part.endsWith('**')) return <strong key={i} className="font-bold text-indigo-950 dark:text-indigo-200">{part.slice(2, -2)}</strong>;
      return part;
    });
  };
  lines.forEach((line, i) => {
    const trim = line.trim();
    if (!trim) { flushList(); return; }
    if (trim.startsWith('* ') || trim.startsWith('- ') || trim.startsWith('• ')) {
      listBuffer.push(<li key={`li-${i}`}>{parseLine(trim.replace(/^[\*\-\•]\s*/, ''))}</li>);
    } else {
      flushList();
      if (trim.startsWith('### ')) elements.push(<h4 key={`h4-${i}`} className="font-bold text-sm uppercase tracking-wide mt-3 mb-1 text-indigo-800 dark:text-indigo-300">{parseLine(trim.substring(4))}</h4>);
      else if (trim.startsWith('## ')) elements.push(<h3 key={`h3-${i}`} className="font-bold text-base mt-4 mb-2 text-indigo-900 dark:text-indigo-100">{parseLine(trim.substring(3))}</h3>);
      else elements.push(<p key={`p-${i}`} className="mb-2 last:mb-0">{parseLine(trim)}</p>);
    }
  });
  flushList();
  return (
    <div className="mt-4 p-4 bg-indigo-50 dark:bg-indigo-950/40 rounded-xl border border-indigo-100 dark:border-indigo-900 text-sm text-indigo-900 dark:text-indigo-200 leading-relaxed animate-in fade-in slide-in-from-top-2 duration-300">
      <div className="flex items-center gap-2 mb-3 border-b border-indigo-200 dark:border-indigo-800 pb-2">
         <BrainCircuit className="w-4 h-4 text-indigo-600 dark:text-indigo-400" />
         <span className="font-bold text-indigo-700 dark:text-indigo-300 text-xs uppercase tracking-wider">AI Assistant Response</span>
      </div>
      <div className="space-y-1">{elements}</div>
    </div>
  );
};

// --- MAIN APP COMPONENT ---

export default function App() {
  // --- STATE ---
  const [nurses, setNurses] = useState<Nurse[]>(() => {
    const saved = localStorage.getItem('nurses');
    return saved ? JSON.parse(saved) : [];
  });

  const [currentUser, setCurrentUser] = useState<Nurse | null>(() => {
    const savedId = localStorage.getItem('currentUserId');
    const savedNurses = localStorage.getItem('nurses');
    if (!savedId || !savedNurses) return null;
    const list: Nurse[] = JSON.parse(savedNurses);
    return list.find(n => n.id === savedId) || null;
  });

  const [isDarkMode, setIsDarkMode] = useState(() => JSON.parse(localStorage.getItem('darkMode') || 'false'));
  const [view, setView] = useState<ViewState>('DASHBOARD');
  const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
  const [patients, setPatients] = useState<Patient[]>(() => JSON.parse(localStorage.getItem('patients') || '[]'));
  const [medications, setMedications] = useState<Medication[]>(() => JSON.parse(localStorage.getItem('medications') || '[]'));
  const [logs, setLogs] = useState<MedicationLog[]>(() => JSON.parse(localStorage.getItem('logs') || '[]'));

  const [isAddPatientOpen, setIsAddPatientOpen] = useState(false);
  const [editingPatient, setEditingPatient] = useState<Patient | null>(null);
  const [isAddMedOpen, setIsAddMedOpen] = useState(false);
  const [editingMed, setEditingMed] = useState<Medication | null>(null);
  const [formFrequency, setFormFrequency] = useState<FrequencyType>(FrequencyType.STAT); 
  const [loggingMed, setLoggingMed] = useState<Medication | null>(null);
  const [expandedHistoryMedId, setExpandedHistoryMedId] = useState<string | null>(null);
  const [aiQuery, setAiQuery] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [dashboardSort, setDashboardSort] = useState<'TIME' | 'PATIENT' | 'MEDICATION'>('TIME');
  const [isCreateProfileOpen, setIsCreateProfileOpen] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isProcessingAudio, setIsProcessingAudio] = useState(false);
  const [selectedMedIds, setSelectedMedIds] = useState<Set<string>>(new Set());
  const [drugInfoModal, setDrugInfoModal] = useState({ isOpen: false, medName: '', loading: false, content: '' });
  const [notificationPermission, setNotificationPermission] = useState<NotificationPermission>('default');
  const [alertedDoses, setAlertedDoses] = useState<Set<string>>(new Set());
  const [confirmConfig, setConfirmConfig] = useState({ isOpen: false, title: '', message: '', onConfirm: () => {} });

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const nameInputRef = useRef<HTMLInputElement>(null);
  const doseInputRef = useRef<HTMLInputElement>(null);
  const formInputRef = useRef<HTMLSelectElement>(null);
  const routeInputRef = useRef<HTMLSelectElement>(null);
  const freqInputRef = useRef<HTMLSelectElement>(null);
  const intervalInputRef = useRef<HTMLInputElement>(null);
  const notesInputRef = useRef<HTMLTextAreaElement>(null);

  // --- EFFECTS ---
  useEffect(() => {
    localStorage.setItem('darkMode', JSON.stringify(isDarkMode));
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  useEffect(() => localStorage.setItem('patients', JSON.stringify(patients)), [patients]);
  useEffect(() => localStorage.setItem('medications', JSON.stringify(medications)), [medications]);
  useEffect(() => localStorage.setItem('logs', JSON.stringify(logs)), [logs]);
  useEffect(() => localStorage.setItem('nurses', JSON.stringify(nurses)), [nurses]);
  useEffect(() => {
    if (currentUser) localStorage.setItem('currentUserId', currentUser.id);
    else localStorage.removeItem('currentUserId');
  }, [currentUser]);

  useEffect(() => { setSelectedMedIds(new Set()); }, [selectedPatientId, view]);
  useEffect(() => { if ('Notification' in window) setNotificationPermission(Notification.permission); }, []);

  useEffect(() => {
    if (notificationPermission !== 'granted') return;
    const checkDoses = () => {
      const now = Date.now();
      medications.forEach(med => {
        if (!med.nextDueAt || med.frequency === FrequencyType.PRN || med.isCompleted) return;
        if (med.nextDueAt <= now && (now - med.nextDueAt) < 86400000) {
          const key = `${med.id}_${med.nextDueAt}`;
          if (!alertedDoses.has(key)) {
            const patient = patients.find(p => p.id === med.patientId);
            new Notification(`Med Due: ${med.name}`, { body: `${patient?.name || 'Unknown'} - ${med.dose} ${med.route}`, tag: key });
            setAlertedDoses(prev => new Set(prev).add(key));
          }
        }
      });
    };
    const intervalId = setInterval(checkDoses, 30000);
    checkDoses();
    return () => clearInterval(intervalId);
  }, [medications, patients, notificationPermission, alertedDoses]);

  // --- HANDLERS ---
  const handleManualLog = (medId: string, status: LogStatus, timestamp: number, notes?: string) => {
    const med = medications.find(m => m.id === medId);
    if (!med || !currentUser) return;
    let nextDue: number | null = med.nextDueAt;
    let completed = med.isCompleted;
    if (med.frequency === FrequencyType.STAT) { nextDue = null; completed = true; }
    else if (med.frequency !== FrequencyType.PRN) {
      const interval = med.intervalHours * 3600000;
      nextDue = status === 'SERVED' ? timestamp + interval : (med.nextDueAt || timestamp) + interval;
    }
    setMedications(prev => prev.map(m => m.id === medId ? { ...m, lastServedAt: status === 'SERVED' ? timestamp : m.lastServedAt, nextDueAt: nextDue, isCompleted: completed } : m));
    setLogs(prev => [...prev, { id: generateId(), medicationId: medId, servedAt: timestamp, status, notes, nurseId: currentUser.id, nurseName: currentUser.name, nurseInitials: currentUser.initials, nurseColor: currentUser.color }]);
    setLoggingMed(null);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mime = MediaRecorder.isTypeSupported('audio/webm') ? 'audio/webm' : 'audio/mp4';
      const recorder = new MediaRecorder(stream, { mimeType: mime });
      mediaRecorderRef.current = recorder;
      audioChunksRef.current = [];
      recorder.ondataavailable = e => e.data.size > 0 && audioChunksRef.current.push(e.data);
      recorder.onstop = async () => {
        setIsProcessingAudio(true);
        const reader = new FileReader();
        reader.readAsDataURL(new Blob(audioChunksRef.current, { type: mime }));
        reader.onloadend = async () => {
          const res = await parseMedicationFromAudio((reader.result as string).split(',')[1], mime);
          if (res.name && nameInputRef.current) nameInputRef.current.value = res.name;
          if (res.dose && doseInputRef.current) doseInputRef.current.value = res.dose;
          if (res.frequency && freqInputRef.current) { freqInputRef.current.value = res.frequency; setFormFrequency(res.frequency); }
          setIsProcessingAudio(false);
          setIsRecording(false);
          stream.getTracks().forEach(t => t.stop());
        };
      };
      recorder.start();
      setIsRecording(true);
    } catch { alert("Mic access denied"); }
  };

  const exportData = () => {
    const csv = [["Date", "Time", "Patient", "Room", "Medication", "Dose", "Route", "Frequency", "Status", "Nurse", "Notes"].join(",")];
    patients.forEach(p => medications.filter(m => m.patientId === p.id).forEach(m => {
      const medLogs = logs.filter(l => l.medicationId === m.id).sort((a, b) => a.servedAt - b.servedAt);
      if (medLogs.length === 0) csv.push([`"-"`,`"-"`,`"${p.name}"`,`"${p.roomNumber || ''}"`,`"${m.name}"`,`"${m.dose}"`,`"${m.route}"`,`"${m.frequency}"`,`"${m.isCompleted ? 'COMPLETED' : 'ACTIVE'}"`,`"-"`,`"${m.notes || ''}"`].join(","));
      else medLogs.forEach(l => {
        const d = new Date(l.servedAt);
        csv.push([`"${d.toLocaleDateString()}"`,`"${d.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}"`,`"${p.name}"`,`"${p.roomNumber || ''}"`,`"${m.name}"`,`"${m.dose}"`,`"${m.route}"`,`"${m.frequency}"`,`"${l.status}"`,`"${l.nurseName}"`,`"${(m.notes || '') + ' ' + (l.notes || '')}"`].join(","));
      });
    }));
    const a = document.createElement("a");
    a.href = window.URL.createObjectURL(new Blob([csv.join("\n")], { type: "text/csv" }));
    a.download = `nurseflow_export_${new Date().toISOString().slice(0,10)}.csv`;
    a.click();
  };

  const upcomingDoses = useMemo(() => {
    const list = medications.filter(m => m.nextDueAt !== null && !m.isCompleted && m.frequency !== FrequencyType.PRN).map(m => ({ ...m, p: patients.find(p => p.id === m.patientId) }));
    return list.sort((a, b) => {
      if (dashboardSort === 'TIME') return (a.nextDueAt || 0) - (b.nextDueAt || 0);
      if (dashboardSort === 'PATIENT') return (a.p?.name || '').localeCompare(b.p?.name || '');
      return a.name.localeCompare(b.name);
    });
  }, [medications, patients, dashboardSort]);

  // --- RENDER FUNCTIONS ---
  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-100 dark:bg-slate-900 flex flex-col items-center justify-center p-6">
        <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-lg border border-slate-200 p-6 w-full max-w-md">
          <h2 className="text-xl font-bold mb-6 flex items-center gap-2 dark:text-white"><User className="text-teal-600" /> Sign In</h2>
          <div className="grid grid-cols-2 gap-4">
            {nurses.map(n => (
              <button key={n.id} onClick={() => setCurrentUser(n)} className="flex flex-col items-center p-4 rounded-xl border bg-slate-50 dark:bg-slate-700/50">
                <div className={`w-12 h-12 rounded-full flex items-center justify-center font-bold mb-2 ${n.color}`}>{n.initials}</div>
                <span className="font-bold text-sm dark:text-slate-200">{n.name}</span>
              </button>
            ))}
            <button onClick={() => setIsCreateProfileOpen(true)} className="flex flex-col items-center justify-center p-4 rounded-xl border border-dashed border-slate-300 text-slate-400">
              <Plus className="mb-2" /> <span className="font-bold text-sm">New Profile</span>
            </button>
          </div>
        </div>
        <Modal isOpen={isCreateProfileOpen} onClose={() => setIsCreateProfileOpen(false)} title="Create New Profile">
          <form onSubmit={e => {
            e.preventDefault();
            const fd = new FormData(e.currentTarget);
            const n: Nurse = { id: generateId(), name: fd.get('name') as string, initials: (fd.get('initials') as string).toUpperCase(), designation: fd.get('designation') as string, color: AVATAR_COLORS[Math.floor(Math.random() * AVATAR_COLORS.length)] };
            setNurses(prev => [...prev, n]);
            setCurrentUser(n);
            setIsCreateProfileOpen(false);
          }} className="space-y-4">
            <input name="name" required className="w-full p-3 bg-slate-50 dark:bg-slate-700 border rounded-xl dark:text-white" placeholder="Full Name" />
            <input name="initials" required maxLength={3} className="w-full p-3 bg-slate-50 dark:bg-slate-700 border rounded-xl dark:text-white" placeholder="Initials" />
            <select name="designation" className="w-full p-3 bg-slate-50 dark:bg-slate-700 border rounded-xl dark:text-white"><option value="RN">RN</option><option value="LPN">LPN</option></select>
            <button type="submit" className="w-full bg-teal-600 text-white font-bold py-3 rounded-xl">Create</button>
          </form>
        </Modal>
