    const med: Medication = { ...m, id: generateId(), lastServedAt: null, nextDueAt: m.frequency === FrequencyType.STAT ? Date.now() : null, isCompleted: false };
    setMedications(prev => [...prev, med]);
    setIsAddMedOpen(false);
  }
