        </div>
        <div className="flex bg-slate-200 dark:bg-slate-800 p-1 rounded-lg">
          <button onClick={() => setDashboardSort('TIME')} className={`px-3 py-1 text-xs font-bold rounded-md transition-all ${dashboardSort === 'TIME' ? 'bg-white dark:bg-slate-700 shadow-sm text-teal-600' : 'text-slate-500'}`}>Time</button>
          <button onClick={() => setDashboardSort('PATIENT')} className={`px-3 py-1 text-xs font-bold rounded-md transition-all ${dashboardSort === 'PATIENT' ? 'bg-white dark:bg-slate-700 shadow-sm text-teal-600' : 'text-slate-500'}`}>Patient</button>
        </div>
      </header>

      {upcomingDoses.length === 0 ? (
        <div className="flex flex-col items-center justify-center pt-20">
