          <p className="text-slate-400 mt-4">All meds served. You're caught up!</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {upcomingDoses.map(m => {
            const isOverdue = m.nextDueAt! < Date.now();
            return (
              <div key={m.id} className={`p-4 bg-white dark:bg-slate-800 rounded-xl border-2 shadow-sm flex justify-between items-center transition-all ${isOverdue ? 'border-rose-100 dark:border-rose-900/30' : 'border-slate-50 dark:border-slate-800'}`}>
