        <Modal isOpen={isAddMedOpen} onClose={() => setIsAddMedOpen(false)} title="Medication Order">
          <button onClick={isRecording ? () => mediaRecorderRef.current?.stop() : startRecording} className={`w-full py-6 mb-6 rounded-2xl flex flex-col items-center gap-2 transition-all border-2 border-dashed ${isRecording ? 'bg-rose-50 border-rose-200 text-rose-600' : 'bg-indigo-50 border-indigo-200 text-indigo-600'}`}>
            {isProcessingAudio ? <Loader2 className="animate-spin w-8 h-8" /> : isRecording ? <Square className="w-8 h-8" /> : <Mic className="w-8 h-8" />}
            <span className="text-xs font-black uppercase tracking-widest">{isProcessingAudio ? 'AI Processing...' : isRecording ? 'Recording...' : 'Voice Dictate Order'}</span>
          </button>
          <form onSubmit={e => {
            e.preventDefault();
            const fd = new FormData(e.currentTarget);
            const freq = fd.get('frequency') as FrequencyType;
            const med: Medication = { 
              patientId: selectedPatientId!, 
              id: generateId(),
              name: fd.get('name') as string, 
              dose: fd.get('dose') as string, 
              route: fd.get('route') as string, 
              frequency: freq, 
              intervalHours: FREQUENCY_HOURS[freq], 
              notes: fd.get('notes') as string,
              lastServedAt: null,
              nextDueAt: freq === FrequencyType.STAT ? Date.now() : null,
              isCompleted: false
            };
            setMedications(prev => [...prev, med]);
            setIsAddMedOpen(false);
          }} className="space-y-4">
            <input name="name" ref={nameInputRef} required className="w-full p-4 bg-slate-50 dark:bg-slate-700 rounded-2xl border-0 dark:text-white" placeholder="Drug Name (e.g. Ciprofloxacin)" />
            <div className="grid grid-cols-2 gap-4">
              <input name="dose" ref={doseInputRef} required className="w-full p-4 bg-slate-50 dark:bg-slate-700 rounded-2xl border-0 dark:text-white" placeholder="Dose (e.g. 500mg)" />
              <select name="route" className="w-full p-4 bg-slate-50 dark:bg-slate-700 rounded-2xl border-0 dark:text-white"><option value="PO">PO (Oral)</option><option value="IV">IV</option><option value="IM">IM</option><option value="SC">Subcut</option></select>
            </div>
            <select name="frequency" ref={freqInputRef} className="w-full p-4 bg-slate-50 dark:bg-slate-700 rounded-2xl border-0 dark:text-white"><option value="STAT">STAT (Now)</option><option value="DAILY">Daily</option><option value="BD">Twice Daily (BID)</option><option value="TID">Three Times (TID)</option><option value="PRN">PRN (As Needed)</option></select>
            <textarea name="notes" className="w-full p-4 bg-slate-50 dark:bg-slate-700 rounded-2xl border-0 dark:text-white" placeholder="Instructions/Notes" />
            <button type="submit" className="w-full bg-teal-600 text-white font-black py-4 rounded-2xl">Add to MAR</button>
          </form>
        </Modal>

        <Modal isOpen={!!loggingMed} onClose={() => setLoggingMed(null)} title="Log Administration">
          <form onSubmit={e => { 
            e.preventDefault(); 
            const fd = new FormData(e.currentTarget); 
            handleManualLog(loggingMed!.id, fd.get('status') as LogStatus, Date.now(), fd.get('notes') as string); 
          }} className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <label className="cursor-pointer group">
                <input type="radio" name="status" value="SERVED" defaultChecked className="hidden peer" />
                <div className="p-6 border-2 rounded-2xl transition-all peer-checked:border-teal-500 peer-checked:bg-teal-50 dark:peer-checked:bg-teal-900/20 text-center font-black dark:text-white">GIVEN</div>
              </label>
              <label className="cursor-pointer group">
                <input type="radio" name="status" value="MISSED" className="hidden peer" />
                <div className="p-6 border-2 rounded-2xl transition-all peer-checked:border-rose-500 peer-checked:bg-rose-50 dark:peer-checked:bg-rose-900/20 text-center font-black dark:text-white">MISSED</div>
              </label>
            </div>
            <textarea name="notes" className="w-full p-4 bg-slate-50 dark:bg-slate-700 rounded-2xl border-0 dark:text-white" placeholder="Comments (e.g. refused, patient sleeping)" />
            <button type="submit" className="w-full bg-slate-900 text-white font-black py-4 rounded-2xl">Submit to Record</button>
          </form>
        </Modal>

        <Modal isOpen={drugInfoModal.isOpen} onClose={() => setDrugInfoModal(p => ({ ...p, isOpen: false }))} title={drugInfoModal.medName}>
          {drugInfoModal.loading ? <div className="p-12 text-center text-indigo-600"><Loader2 className="animate-spin mx-auto w-10 h-10 mb-4" /><p className="font-bold">Consulting Clinical AI...</p></div> : <AiResponseDisplay text={drugInfoModal.content} />}
        </Modal>
      </main>
    </div>
  );
}

