              frequency: freq, 
              intervalHours: interval, 
              notes: fd.get('notes') as string,
            };

            if (editingMed) {
              setMedications(prev => prev.map(m => m.id === editingMed.id ? { ...m, ...medData, nextDueAt: (m.frequency !== freq && freq === 'STAT') ? Date.now() : m.nextDueAt } : m));
            } else {
              setMedications(prev => [...prev, { 
                ...medData, 
                id: generateId(), 
                lastServedAt: null, 
                nextDueAt: freq === FrequencyType.STAT ? Date.now() : null, 
                isCompleted: false 
              }]);
            }
            setIsAddMedOpen(false);
            setEditingMed(null);
          }} className="space-y-4">
            <div>
               <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-2 block">Medication Name</label>
               <input name="name" ref={nameInputRef} defaultValue={editingMed?.name} required className={INPUT_CLASS} placeholder="e.g. Ciprofloxacin" />
