        <Modal isOpen={isCreateProfileOpen} onClose={() => setIsCreateProfileOpen(false)} title="Create Profile">
          <form onSubmit={e => {
            e.preventDefault();
            const fd = new FormData(e.currentTarget);
            const n: Nurse = { 
              id: generateId(), 
              name: fd.get('name') as string, 
              initials: (fd.get('initials') as string).toUpperCase(), 
              designation: fd.get('designation') as string, 
              color: AVATAR_COLORS[Math.floor(Math.random() * AVATAR_COLORS.length)] 
            };
            setNurses(prev => [...prev, n]);
            setCurrentUser(n);
            setIsCreateProfileOpen(false);
          }} className="space-y-5">
            <div>
               <label className={LABEL_CLASS}>Full Legal Name</label>
               <input name="name" required className={INPUT_CLASS} placeholder="e.g. Martha Stewart" />
